  #[allow(clippy::clone_on_copy)]
  #[allow(clippy::vec_init_then_push)]
  pub fn invoke_signed(&self, signers_seeds: &[&[&[u8]]]) -> solana_program_error::ProgramResult {
          let args = InitializeVaultInstructionArgs {
                                                              stake_amount: self.instruction.stake_amount.clone().expect("stake_amount is not set"),
                                                                  checkin_interval: self.instruction.checkin_interval.clone().expect("checkin_interval is not set"),
                                    };
        let instruction = InitializeVaultCpi {
        __program: self.instruction.__program,
                  
          owner: self.instruction.owner.expect("owner is not set"),
                  
          nominee: self.instruction.nominee.expect("nominee is not set"),
                  
          vault: self.instruction.vault.expect("vault is not set"),
                  
          mint: self.instruction.mint.expect("mint is not set"),
                  
          owner_ata: self.instruction.owner_ata.expect("owner_ata is not set"),
                  
          vault_ata: self.instruction.vault_ata.expect("vault_ata is not set"),
                  
          usdc_mint: self.instruction.usdc_mint.expect("usdc_mint is not set"),
                  
          owner_usdc_ata: self.instruction.owner_usdc_ata.expect("owner_usdc_ata is not set"),
                  
          platform_wallet: self.instruction.platform_wallet.expect("platform_wallet is not set"),
                  
          platform_usdc_ata: self.instruction.platform_usdc_ata.expect("platform_usdc_ata is not set"),
                  
          token_program: self.instruction.token_program.expect("token_program is not set"),
                  
          associated_token_program: self.instruction.associated_token_program.expect("associated_token_program is not set"),
                  
          system_program: self.instruction.system_program.expect("system_program is not set"),
                          __args: args,
            };
    instruction.invoke_signed_with_remaining_accounts(signers_seeds, &self.instruction.__remaining_accounts)
  }
